INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05080', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '某社會機構徵聘部門主管，請應聘者用一句話形容自己優點，下列選項何者最容易獲得 主考官青睞？', '["寧為雞口，毋為牛後", "舌粲蓮花，辯才無礙", "灑掃應對，無一不精", "運籌帷幄，決策明快"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05081', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「什麼樣的人生才是真正有光彩有意義的？面對別人的輝煌時刻又該如何正視自己的平 庸？在大千世界中，每個人都有一個適當的定位。正確地確立自己在生活與事業中的位 置，正確地評估自己的能力和價值，不嫉妒別人，以一顆平常之心善待別人也善待自己， 哪怕是一份最平常的人生也自有它的珍貴！」 下列選項，何者符合上文旨意？', '["平庸者力爭上游才能出人頭地", "嫉妒反而能激勵人心擺脫平庸", "要超越極限才能顯現生命光彩", "一枝草一點露，天無絕人之路"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05082', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「美國的研究發現，儘管茲卡病毒已橫行全球近七十年，不同病毒株的基因差異卻不大。 例如目前在美洲肆虐的病毒株與早先在法屬波里尼西亞發現的，幾乎無法分辨。針對病 媒蚊的新研究顯示，茲卡病毒從一開始就具備強大的致病力並可能造成大流行。此外， 公衛官員之前可能不知道茲卡病毒的潛在威力，因為這種病毒過去大多在偏遠地區傳 播，直到不久前才大肆擴張勢力範圍。」 本段文意主要在說明茲卡病毒的：', '["防治", "變種", "源流", "病徵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05083', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「在一篇〈命運三騎士〉的文章裡，我提到從事文化事業工作一段時間後，對大學、高 中和初中生活的三段回憶。裡面有一段話說：『今夜，我便如此地與他們遭逢；他們靜 默地展現，提醒我曾經擁有的以及失落的人格樣貌。在地上爬的毛毛蟲，儘管變成了在 空中飛的蝴蝶，但蝴蝶的翅膀只是華麗的外衣，牠生命的深層結構依然是毛毛蟲的，這 大概是牠無法擺脫的命運吧？』」 根據上文，下列敘述最切近作者想傳達的旨意是：', '["蝴蝶效應的擴大", "原生環境的影響", "滄海桑田的變化", "浴火鳳凰的重生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05084', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '政府良好的施政品質，常是一個國家進步的重要關鍵。對於施政要領，《孟子‧離婁上》 提出：「徒善不足以為政，徒法不能以自行。」依孟子所論，下列敘述何者正確？', '["強調擁有善心善念就能產生良好的政治", "強調建立法令政策，才能達成施政目的", "強調建立了法令政策，必須確實執行才能發揮作用", "認為進用善人而不黜退惡人，不能在政治上有所建樹"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05085', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「大道廢，有仁義；慧智出，有大偽；六親不和，有孝慈；國家昏亂，有忠臣。」（《老 子‧十八章》） 關於本文的闡釋，下列何者正確？', '["「大道廢，有仁義」指：當大道廢棄，恆需提倡仁義，故仁義實不可或缺", "「慧智出，有大偽」指：當智巧紛陳，就會出現虛偽不實，二者相伴而生", "「六親不和，有孝慈」指：家庭紛爭難免，唯有孝順與慈愛能使家庭和諧", "「國家昏亂，有忠臣」指：國家昏亂時，更依賴忠臣安邦定國，建立秩序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05086', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「信安郡有石室山。晉時，王質伐木；至，見童子數人棊而歌。質因聽之。童子以一物 與質，如棗核。質含之，不覺饑。俄頃，童子謂曰：『何不去？』質起，視斧柯爛盡。 既歸，無復時人。」（《述異記‧斧柯爛》）下列何者最接近此一故事所要表達的意旨？', '["好奇之心，人皆有之", "山中一日，世上千年", "雖遇仙人，或非幸事", "山中奇事，所在多有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05087', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「粟，稼而生者也；若布與帛，必蠶績而後成者也；其他所以養生之具，皆待人力而後 完也；吾皆賴之。然人不可遍爲，宜乎各致其能以相生也。故君者，理我所以生者也； 而百官者，承君之化者也。任有大小，惟其所能，若器皿焉。（韓愈〈圬者王承福傳〉）」 下列選項，何者符合上文意旨？', '["工欲善其事，必先利其器。居是邦也，事其大夫之賢者，友其士之仁者", "天地之大也，人猶有所憾。故君子語大，天下莫能載焉；語小，天下莫能破焉", "生之者眾，食之者寡；為之者疾，用之者舒；則財恆足矣。仁者以財發身，不仁者以 身發財", "有大人之事，有小人之事。且一人之身，而百工之所為備；如必自為而後用之，是率 天下而路也"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05088', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「可是他在確定罹患癌症之後，常常亂發脾氣，卻最聽我的話，我必須每逢休假就回家， 做為他和母親的平衡桿，……我偽裝成一個還算孝順的兒子，四年多的日子，每天至少 打一次電話，一至兩週陪他到醫院回診，斷斷續續的住院則幫忙料理打點，休假就乖乖 的回家，陪他們吃淡而無味的菜和飯。」下列選項何者較貼近作者的處境？', '["漫漫無期的奔波讓人心灰意冷", "親人生病與長期照料是種煎熬", "強顏歡笑讓作者覺得痛苦無奈", "有能力照料雙親就要及時行孝"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05089', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '描述自然現象，可以比擬作「人情往來」的方式，使文章更為生動。下列對於觀海的描 寫，何者符合此一特色？', '["海的面貌當然不僅於此，你可以在高高的展望臺上，遠眺無邊大洋，遍數附近羅列的 島嶼", "一座島就那樣「放」在海邊，只有一天特定的某些時候，海水會像摩西渡過紅海那樣， 退出一條路來", "從高處看海，最好也不要太久，因為看久了會目眩神馳，會著魔般的忘了自己。就像 浪花洗過礁岩一樣", "過不了許久，卻又像悔悟了似的，海水一片片、一片片的把沙灘還了出來，像情人間 的小小齟齬，總有人要讓步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
